class SketchJoinOrderPlannerCartesianCostRegressionTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final int EXACT_STATEMENT_LOOKUP_MASK = componentMask(SketchBasedJoinEstimator.Component.S,
			SketchBasedJoinEstimator.Component.P, SketchBasedJoinEstimator.Component.O);

	@Test
	void plannerDoesNotUnderpriceDisconnectedEndpointDomainsBeforeBridge() {
		StubSketchStatementSource store = new StubSketchStatementSource();
		IRI rdfType = VF.createIRI("urn:rdfType");
		IRI aasType = VF.createIRI("urn:AssetAdministrationShell");
		IRI value = VF.createIRI("urn:value");
		IRI assetInformation = VF.createIRI("urn:assetInformation");
		IRI specificAssetId = VF.createIRI("urn:specificAssetId");
		IRI submodel = VF.createIRI("urn:submodel");
		IRI submodelElement = VF.createIRI("urn:submodelElement");
		IRI idShort = VF.createIRI("urn:idShort");
		for (int i = 0; i < 100; i++) {
			Resource aas = VF.createIRI("urn:aas:" + i);
			Resource assetInfo = VF.createIRI("urn:asset-info:" + i);
			Resource driveId = VF.createIRI("urn:drive-id:" + i);
			Resource submodelNode = VF.createIRI("urn:submodel:" + i);
			Resource element = VF.createIRI("urn:element:" + i);
			Resource ratedPower = VF.createIRI("urn:rated-power:" + i);
			store.add(VF.createStatement(aas, rdfType, aasType));
			store.add(VF.createStatement(aas, assetInformation, assetInfo));
			store.add(VF.createStatement(assetInfo, specificAssetId, driveId));
			store.add(VF.createStatement(driveId, value, VF.createLiteral("DriveUnit")));
			store.add(VF.createStatement(aas, submodel, submodelNode));
			store.add(VF.createStatement(submodelNode, submodelElement, element));
			store.add(VF.createStatement(element, value, ratedPower));
			store.add(VF.createStatement(ratedPower, idShort, VF.createLiteral("ratedPower")));
			store.add(VF.createStatement(ratedPower, value, VF.createLiteral(20.0d)));
		}

		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store, config());
		estimator.rebuild();

		StatementPattern aasTypePattern = new StatementPattern(Var.of("aas"), Var.of("type", rdfType),
				Var.of("aasType", aasType));
		StatementPattern driveValuePattern = new StatementPattern(Var.of("driveId"), Var.of("value", value),
				Var.of("driveUnit", VF.createLiteral("DriveUnit")));
		StatementPattern assetInformationPattern = pattern("aas", assetInformation, "assetInfo");
		StatementPattern specificAssetIdPattern = pattern("assetInfo", specificAssetId, "driveId");
		StatementPattern submodelPattern = pattern("aas", submodel, "submodel");
		StatementPattern submodelElementPattern = pattern("submodel", submodelElement, "submodelElement");
		StatementPattern valuePathPattern = pattern("submodelElement", value, "p1");
		StatementPattern idShortPattern = new StatementPattern(Var.of("p1"), Var.of("idShort", idShort),
				Var.of("ratedPower", VF.createLiteral("ratedPower")));
		StatementPattern propertyValuePattern = pattern("p1", value, "v1");
		List<TupleExpr> args = List.of(aasTypePattern, driveValuePattern, assetInformationPattern,
				specificAssetIdPattern, submodelPattern, submodelElementPattern, valuePathPattern, idShortPattern,
				propertyValuePattern);

		JoinOrderPlanner.PlanningAttempt attempt = estimator.planJoinOrderAttempt(args, Set.of(),
				JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING, aasEndpointCostModel(aasTypePattern,
						driveValuePattern, assetInformationPattern, specificAssetIdPattern, submodelPattern,
						submodelElementPattern, valuePathPattern, idShortPattern, propertyValuePattern),
				List.of());

		assertTrue(attempt.getPlan().isPresent(), "Expected planner to produce an AAS-shaped endpoint bridge plan");
		JoinOrderPlanner.JoinOrderPlan plan = attempt.getPlan().get();
		List<TupleExpr> orderedArgs = plan.getOrderedArgs();
		assertTrue(orderedArgs.indexOf(specificAssetIdPattern) < orderedArgs.indexOf(driveValuePattern),
				"DriveUnit endpoint scan must not be prepared before the connecting specificAssetId bridge without "
						+ "charging the cartesian product: order=" + orderedArgs + ", steps=" + plan.getSteps()
						+ ", totalWork=" + plan.getEstimatedTotalWork());

		JoinFactorCostModel costModel = aasEndpointCostModel(aasTypePattern, driveValuePattern,
				assetInformationPattern, specificAssetIdPattern, submodelPattern, submodelElementPattern,
				valuePathPattern, idShortPattern, propertyValuePattern);
		JoinOrderPlanner.JoinOrderPlan disconnectedEndpointFirst = estimator
				.estimateJoinOrder(args, Set.of(), JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING, costModel,
						List.of())
				.orElseThrow();
		double disconnectedDriveUnitStepWork = disconnectedEndpointFirst.getSteps().get(1).getStepWorkRows();
		assertTrue(disconnectedDriveUnitStepWork >= 1_000_000.0d,
				"Disconnected AAS endpoint scans must be priced as a real cartesian product, not additive work: "
						+ "driveUnitStepWork=" + disconnectedDriveUnitStepWork
						+ ", order=" + disconnectedEndpointFirst.getOrderedArgs()
						+ ", steps=" + disconnectedEndpointFirst.getSteps());
		String disconnectedVector = disconnectedEndpointFirst.getSummaryStringMetrics()
				.get(TelemetryMetricNames.OPTIMIZER_LOGICAL_EXPLORATION);
		assertTrue(!disconnectedVector.contains("cartesianWorkRows=0.0"),
				"Disconnected AAS endpoint scans must retain cartesian risk in the Pareto vector: "
						+ disconnectedVector);
		JoinOrderPlanner.JoinOrderPlan bridgeFirst = estimator
				.estimateJoinOrder(List.of(aasTypePattern, assetInformationPattern, specificAssetIdPattern,
						driveValuePattern, submodelPattern, submodelElementPattern, valuePathPattern, idShortPattern,
						propertyValuePattern), Set.of(), JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING, costModel,
						List.of())
				.orElseThrow();

		assertTrue(bridgeFirst.getEstimatedTotalWork() < disconnectedEndpointFirst.getEstimatedTotalWork(),
				"Disconnected endpoint domains before a two-hop bridge must include cartesian work: "
						+ "disconnectedFirst=" + disconnectedEndpointFirst.getEstimatedTotalWork()
						+ ", bridgeFirst=" + bridgeFirst.getEstimatedTotalWork()
						+ ", disconnectedSteps=" + disconnectedEndpointFirst.getSteps()
						+ ", bridgeSteps=" + bridgeFirst.getSteps());
	}

	private static JoinFactorCostModel aasEndpointCostModel(StatementPattern aasTypePattern,
			StatementPattern driveValuePattern, StatementPattern assetInformationPattern,
			StatementPattern specificAssetIdPattern, StatementPattern submodelPattern,
			StatementPattern submodelElementPattern, StatementPattern valuePathPattern, StatementPattern idShortPattern,
			StatementPattern propertyValuePattern) {
		return (factor, boundVars) -> estimateAasEndpointCost(factor, boundVars, aasTypePattern,
				driveValuePattern, assetInformationPattern, specificAssetIdPattern, submodelPattern,
				submodelElementPattern, valuePathPattern, idShortPattern, propertyValuePattern);
	}

	private static Optional<JoinFactorCostModel.FactorCostEstimate> estimateAasEndpointCost(TupleExpr factor,
			Set<String> boundVars, StatementPattern aasTypePattern, StatementPattern driveValuePattern,
			StatementPattern assetInformationPattern, StatementPattern specificAssetIdPattern,
			StatementPattern submodelPattern, StatementPattern submodelElementPattern,
			StatementPattern valuePathPattern,
			StatementPattern idShortPattern, StatementPattern propertyValuePattern) {
		if (factor == aasTypePattern) {
			return Optional.of(boundVars.contains("aas") ? exactDirectLookup(1.0d, 1.0d)
					: new JoinFactorCostModel.FactorCostEstimate(20_100.0d, 20_100.0d));
		}
		if (factor == driveValuePattern) {
			return Optional.of(boundVars.contains("driveId") ? exactDirectLookup(1.0d, 1.0d)
					: new JoinFactorCostModel.FactorCostEstimate(10_000.0d, 10_000.0d));
		}
		if (factor == assetInformationPattern) {
			return Optional.of(boundVars.contains("aas") ? new JoinFactorCostModel.FactorCostEstimate(1.0d, 1.0d)
					: new JoinFactorCostModel.FactorCostEstimate(10_000.0d, 10_000.0d));
		}
		if (factor == specificAssetIdPattern) {
			if (boundVars.contains("assetInfo") && boundVars.contains("driveId")) {
				return Optional.of(exactDirectLookup(1.0d, 1.0d));
			}
			if (boundVars.contains("assetInfo")) {
				return Optional.of(new JoinFactorCostModel.FactorCostEstimate(1.0d, 1.0d));
			}
			if (boundVars.contains("driveId")) {
				return Optional.of(new JoinFactorCostModel.FactorCostEstimate(1.0d, 1.0d));
			}
			return Optional.of(new JoinFactorCostModel.FactorCostEstimate(10_000.0d, 10_000.0d));
		}
		if (factor == submodelPattern) {
			return Optional.of(boundVars.contains("aas") ? new JoinFactorCostModel.FactorCostEstimate(121.0d, 121.0d)
					: new JoinFactorCostModel.FactorCostEstimate(10_000.0d, 10_000.0d));
		}
		if (factor == submodelElementPattern) {
			return Optional.of(boundVars.contains("submodel")
					? new JoinFactorCostModel.FactorCostEstimate(65.0d, 65.0d)
					: new JoinFactorCostModel.FactorCostEstimate(10_000.0d, 10_000.0d));
		}
		if (factor == valuePathPattern) {
			return Optional.of(boundVars.contains("submodelElement")
					? new JoinFactorCostModel.FactorCostEstimate(4_700_000.0d, 4_700_000.0d)
					: new JoinFactorCostModel.FactorCostEstimate(10_000_000.0d, 10_000_000.0d));
		}
		if (factor == idShortPattern) {
			return Optional.of(boundVars.contains("p1") ? new JoinFactorCostModel.FactorCostEstimate(1.0d, 34.0d)
					: new JoinFactorCostModel.FactorCostEstimate(10_000.0d, 10_000.0d));
		}
		if (factor == propertyValuePattern) {
			return Optional.of(boundVars.contains("p1") ? new JoinFactorCostModel.FactorCostEstimate(44.0d, 44.0d)
					: new JoinFactorCostModel.FactorCostEstimate(10_000.0d, 10_000.0d));
		}
		return Optional.empty();
	}

	private static JoinFactorCostModel.FactorCostEstimate exactDirectLookup(double workRows, double outputRows) {
		return new JoinFactorCostModel.FactorCostEstimate(workRows, outputRows, Map.of(), Map.of(), true, true,
				EXACT_STATEMENT_LOOKUP_MASK, 0, workRows);
	}

	private static StatementPattern pattern(String subjVar, IRI pred, String objVar) {
		return new StatementPattern(Var.of(subjVar), Var.of("p", pred), Var.of(objVar));
	}

	private static int componentMask(SketchBasedJoinEstimator.Component... components) {
		int mask = 0;
		for (SketchBasedJoinEstimator.Component component : components) {
			mask |= 1 << component.ordinal();
		}
		return mask;
	}

	private static SketchBasedJoinEstimator.Config config() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withNominalEntries(64)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}
}
